mapper.update:
UPDATE fit_analysis_learning_task task
INNER JOIN fit_analysis fa ON fa.id = task.fit_analysis_id
INNER JOIN application_case ac ON ac.id = fa.application_case_id
SET task.completed = #{completed},
    task.completed_at = IF(#{completed}, CURRENT_TIMESTAMP, NULL)
WHERE task.id = #{taskId}
  AND task.fit_analysis_id = #{fitAnalysisId}
  AND ac.user_id = #{userId}
  AND ac.deleted_at IS NULL

mapper.select:
SELECT *
FROM fit_analysis_learning_task
WHERE id = #{taskId}
  AND fit_analysis_id = #{fitAnalysisId}
